def get_total_subtargets() -> int:
    """Επιστρέφει τον συνολικό αριθμό υποστόχων (έλεγχος ορθότητας)."""
    return sum(len(sdg["subtargets"]) for sdg in SDG_DATA.values())


def get_subtarget_title(code: str) -> str | None:
    """Επιστρέφει τον τίτλο ενός υποστόχου από το code (π.χ. '8.5')."""
    if "." not in code:
        return None
    sdg_part = code.split(".")[0]
    try:
        sdg_id = int(sdg_part)
    except ValueError:
        return None
    sdg = SDG_DATA.get(sdg_id)
    if not sdg:
        return None
    return sdg["subtargets"].get(code)
